SELECT l.id, l.user_id AS userId, u.username, u.nickname, l.login_type AS loginType, l.login_ip AS loginIp, l.login_device AS loginDevice, l.login_location AS loginLocation, l.login_status AS loginStatus, l.fail_reason AS failReason, l.created_at AS createdAt FROM user_login_logs l LEFT JOIN users u ON u.id = l.user_id WHERE 1 = 1
AND l.user_id = #{userId}
AND l.login_status = #{loginStatus}
ORDER BY l.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM user_login_logs l
WHERE 1 = 1

    AND l.user_id = #{userId}


    AND l.login_status = #{loginStatus}
